import { useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useMutation, useQuery } from "@tanstack/react-query";
import { Mail, Loader2, Send, Building2, Filter, Eye, EyeOff } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { toast } from "@/hooks/use-toast";

interface Restaurant {
  id: string;
  name: string;
  name_en: string | null;
  email: string;
  city: string | null;
  country: string | null;
  template: string | null;
}

export default function AdminRestaurantBulkEmail() {
  const { t } = useTranslation();
  const [cityFilter, setCityFilter] = useState<string>("all");
  const [templateFilter, setTemplateFilter] = useState<string>("all");
  const [searchQuery, setSearchQuery] = useState("");
  const [subject, setSubject] = useState("");
  const [htmlContent, setHtmlContent] = useState("");
  const [fromName, setFromName] = useState("Xiaoxiong Market");
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showPreview, setShowPreview] = useState(false);

  // Fetch restaurants with emails
  const { data: restaurants = [], isLoading } = useQuery({
    queryKey: ["restaurant-emails"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("id, name, name_en, email, city, country, template")
        .eq("visible", true)
        .not("email", "is", null)
        .neq("email", "")
        .order("city");
      if (error) throw error;
      return data as Restaurant[];
    },
  });

  // Derive filter options
  const cities = useMemo(() => [...new Set(restaurants.map((r) => r.city).filter(Boolean))].sort() as string[], [restaurants]);
  const templates = useMemo(() => [...new Set(restaurants.map((r) => r.template).filter(Boolean))].sort() as string[], [restaurants]);

  // Filter restaurants
  const filteredRestaurants = useMemo(() => {
    let result = restaurants;
    if (cityFilter !== "all") result = result.filter((r) => r.city === cityFilter);
    if (templateFilter !== "all") result = result.filter((r) => r.template === templateFilter);
    if (searchQuery.trim()) {
      const q = searchQuery.trim().toLowerCase();
      result = result.filter((r) => `${r.name} ${r.name_en || ""} ${r.email}`.toLowerCase().includes(q));
    }
    return result;
  }, [restaurants, cityFilter, templateFilter, searchQuery]);

  // Select all filtered
  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      setSelectedIds(new Set(filteredRestaurants.map((r) => r.id)));
    } else {
      setSelectedIds(new Set());
    }
  };

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const selectedRestaurants = useMemo(
    () => restaurants.filter((r) => selectedIds.has(r.id)),
    [restaurants, selectedIds]
  );

  const sendMutation = useMutation({
    mutationFn: async () => {
      if (!subject.trim()) throw new Error(t("admin.restaurantEmail.errorNoSubject", "请输入邮件主题"));
      if (!htmlContent.trim()) throw new Error(t("admin.restaurantEmail.errorNoContent", "请输入邮件内容"));
      if (!selectedRestaurants.length) throw new Error(t("admin.restaurantEmail.errorNoRecipients", "请选择收件餐厅"));

      const recipientEmails = selectedRestaurants.map((r) => r.email);

      const { data, error } = await supabase.functions.invoke("send-restaurant-bulk-email", {
        body: { subject: subject.trim(), htmlContent, recipientEmails, fromName: fromName.trim() },
      });

      if (error) throw error;
      return data;
    },
    onSuccess: (data) => {
      toast({
        title: t("common.success"),
        description: t("admin.restaurantEmail.sendResult", "已发送 {{success}}/{{total}}，失败 {{failed}}", {
          success: data.successCount,
          total: data.total,
          failed: data.failedCount,
        }),
      });
    },
    onError: (error: any) => {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    },
  });

  const allFilteredSelected = filteredRestaurants.length > 0 && filteredRestaurants.every((r) => selectedIds.has(r.id));

  return (
    <div className="space-y-6">
      <div>
        <h1 className="flex items-center gap-2 text-2xl font-bold">
          <Building2 className="h-6 w-6" />
          {t("admin.restaurantEmail.title", "餐厅群发邮件")}
        </h1>
        <p className="mt-1 text-sm text-muted-foreground">
          {t("admin.restaurantEmail.desc", "按城市、类型筛选餐厅并发送邮件")}
        </p>
      </div>

      {/* Filters */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-base">
            <Filter className="h-4 w-4" />
            {t("admin.restaurantEmail.filters", "筛选条件")}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4 md:grid-cols-3">
            <div>
              <Label>{t("admin.restaurantEmail.city", "城市")}</Label>
              <Select value={cityFilter} onValueChange={setCityFilter}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">{t("common.all", "全部")}</SelectItem>
                  {cities.map((city) => (
                    <SelectItem key={city} value={city}>
                      {city} ({restaurants.filter((r) => r.city === city).length})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>{t("admin.restaurantEmail.template", "类型")}</Label>
              <Select value={templateFilter} onValueChange={setTemplateFilter}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">{t("common.all", "全部")}</SelectItem>
                  {templates.map((tmpl) => (
                    <SelectItem key={tmpl} value={tmpl}>
                      {tmpl} ({restaurants.filter((r) => r.template === tmpl).length})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>{t("admin.restaurantEmail.search", "搜索")}</Label>
              <Input
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder={t("admin.restaurantEmail.searchPlaceholder", "餐厅名称或邮箱...")}
              />
            </div>
          </div>

          {/* Stats */}
          <div className="mt-4 flex flex-wrap gap-3">
            <Badge variant="secondary">
              {t("admin.restaurantEmail.matchCount", "匹配: {{count}}", { count: filteredRestaurants.length })}
            </Badge>
            <Badge variant="default">
              {t("admin.restaurantEmail.selectedCount", "已选: {{count}}", { count: selectedIds.size })}
            </Badge>
          </div>
        </CardContent>
      </Card>

      {/* Restaurant list */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center justify-between text-base">
            <span>{t("admin.restaurantEmail.recipients", "收件餐厅")}</span>
            <div className="flex items-center gap-2">
              <Checkbox
                checked={allFilteredSelected}
                onCheckedChange={handleSelectAll}
              />
              <span className="text-sm font-normal text-muted-foreground">
                {t("admin.restaurantEmail.selectAll", "全选当前筛选")}
              </span>
            </div>
          </CardTitle>
        </CardHeader>
        <CardContent className="p-0">
          {isLoading ? (
            <div className="space-y-3 p-6">{[1, 2, 3].map((i) => <Skeleton key={i} className="h-10 w-full" />)}</div>
          ) : filteredRestaurants.length === 0 ? (
            <div className="p-6 text-sm text-muted-foreground">
              {t("admin.restaurantEmail.noResults", "没有匹配的餐厅")}
            </div>
          ) : (
            <div className="max-h-[400px] overflow-y-auto">
              <div className="divide-y divide-border">
                {filteredRestaurants.map((r) => (
                  <label
                    key={r.id}
                    className="flex cursor-pointer items-center gap-3 px-4 py-2.5 hover:bg-muted/50"
                  >
                    <Checkbox
                      checked={selectedIds.has(r.id)}
                      onCheckedChange={() => toggleSelect(r.id)}
                    />
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2">
                        <span className="truncate text-sm font-medium">{r.name}</span>
                        {r.name_en && <span className="truncate text-xs text-muted-foreground">({r.name_en})</span>}
                      </div>
                      <div className="flex items-center gap-2 text-xs text-muted-foreground">
                        <span>{r.email}</span>
                        {r.city && <Badge variant="outline" className="text-[10px] px-1 py-0">{r.city}</Badge>}
                        {r.template && <Badge variant="outline" className="text-[10px] px-1 py-0">{r.template}</Badge>}
                      </div>
                    </div>
                  </label>
                ))}
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Email compose */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">
            {t("admin.restaurantEmail.compose", "编辑邮件")}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid gap-4 md:grid-cols-2">
            <div>
              <Label>{t("admin.restaurantEmail.subject", "邮件主题")}</Label>
              <Input value={subject} onChange={(e) => setSubject(e.target.value)} placeholder={t("admin.restaurantEmail.subjectPlaceholder", "例：小熊市场合作邀请")} />
            </div>
            <div>
              <Label>{t("admin.restaurantEmail.fromName", "发件人名称")}</Label>
              <Input value={fromName} onChange={(e) => setFromName(e.target.value)} />
            </div>
          </div>
          <div>
            <div className="flex items-center justify-between mb-1">
              <Label>{t("admin.restaurantEmail.content", "邮件内容 (HTML)")}</Label>
              <Button variant="ghost" size="sm" onClick={() => setShowPreview(!showPreview)}>
                {showPreview ? <EyeOff className="mr-1 h-3 w-3" /> : <Eye className="mr-1 h-3 w-3" />}
                {showPreview ? t("admin.restaurantEmail.hidePreview", "隐藏预览") : t("admin.restaurantEmail.showPreview", "预览")}
              </Button>
            </div>
            <Textarea
              className="min-h-[200px] font-mono text-xs"
              value={htmlContent}
              onChange={(e) => setHtmlContent(e.target.value)}
              placeholder="<html>...</html>"
            />
          </div>

          {showPreview && htmlContent && (
            <div className="rounded-lg border border-border p-4">
              <Label className="mb-2 block">{t("admin.restaurantEmail.preview", "邮件预览")}</Label>
              <div className="rounded bg-background" dangerouslySetInnerHTML={{ __html: htmlContent }} />
            </div>
          )}

          <div className="flex items-center justify-between pt-4">
            <p className="text-sm text-muted-foreground">
              {t("admin.restaurantEmail.willSendTo", "将发送给 {{count}} 家餐厅", { count: selectedIds.size })}
            </p>
            <Button
              onClick={() => {
                if (!selectedIds.size) {
                  toast({ title: t("common.error"), description: t("admin.restaurantEmail.errorNoRecipients", "请选择收件餐厅"), variant: "destructive" });
                  return;
                }
                const confirmed = window.confirm(
                  t("admin.restaurantEmail.confirmSend", "确认向 {{count}} 家餐厅发送邮件？", { count: selectedIds.size })
                );
                if (confirmed) sendMutation.mutate();
              }}
              disabled={sendMutation.isPending || !selectedIds.size}
            >
              {sendMutation.isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Send className="mr-2 h-4 w-4" />}
              {t("admin.restaurantEmail.send", "发送邮件")}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
